mapper.select:
SELECT m.id, m.menu_name AS menuName, m.menu_type AS menuType, m.parent_id AS parentId, m.path, m.component, m.icon, m.sort_order AS sortOrder, m.permission_code AS permissionCode, m.visible, m.status FROM sys_menu m WHERE m.deleted = 0
AND m.status = #{status}
ORDER BY m.sort_order ASC, m.create_time ASC
